        case (current_state)
            IDLE:
                if (SRO)
                    next_state = RUN;
                else
                    next_state = IDLE;

            RUN:
                if ((addr_reg == SRAM_DEPTH - 1) && dv)
                    next_state = IDLE;
                else
                    next_state = RUN;

            default: next_state = IDLE;
        endcase
    end

    // Address Register Logic (increment only when dv is high)
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            addr_reg <= '0;
        end else begin
            case (current_state)
                IDLE: begin
                    addr_reg <= '0;
                end
                RUN: begin
                    if (dv) begin
                        if (addr_reg < SRAM_DEPTH - 1)
                            addr_reg <= addr_reg + 1;
                        else
                            addr_reg <= addr_reg; // Hold last address
                    end
                end
                default: addr_reg <= '0;
            endcase
        end

        do_acc <= current_state == RUN;
    end

